#include <stdio.h>
#include <stdint.h>

static int64_t gcd_int64(int64_t a, int64_t b) {
    while (b) { int64_t t = a % b; a = b; b = t; }
    return a;
}
static int64_t lcm_int64(int64_t a, int64_t b) {
    return a / gcd_int64(a, b) * b;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t N, a, b, c; scanf("%lld %lld %lld %lld", &N, &a, &b, &c);
        int64_t l_ab = lcm_int64(a, b);
        int64_t l_ac = lcm_int64(a, c);
        int64_t l_bc = lcm_int64(b, c);
        int64_t l_abc = lcm_int64(l_ab, c);
        int64_t low = 1, high = N * (a < b ? (a < c ? a : c) : (b < c ? b : c));
        while (low < high) {
            int64_t mid = low + (high - low) / 2;
            int64_t cnt = mid / a + mid / b + mid / c
                         - mid / l_ab - mid / l_ac - mid / l_bc
                         + mid / l_abc;
            if (cnt >= N) high = mid; else low = mid + 1;
        }
        printf("%lld\n", low);
    }
    return 0;
}

