#!/usr/bin/env python3
import sys, math

def lcm(x, y):
    return x // math.gcd(x, y) * y

def nth_good(N, a, b, c):
    l_ab = lcm(a, b)
    l_ac = lcm(a, c)
    l_bc = lcm(b, c)
    l_abc = lcm(l_ab, c)
    low, high = 1, N * min(a, b, c)
    while low < high:
        mid = (low + high) // 2
        cnt = mid // a + mid // b + mid // c - mid // l_ab - mid // l_ac - mid // l_bc + mid // l_abc
        if cnt >= N:
            high = mid
        else:
            low = mid + 1
    return low

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); a = int(next(it)); b = int(next(it)); c = int(next(it))
        out.append(str(nth_good(N, a, b, c)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

